import React, { useEffect, useMemo, useRef, useState } from 'react';
import axios from 'axios';
import { darkMapStyle } from '../lib/darkMapStyle';
import { formatTimeAgo } from '../lib/time';
import ReportModal from './ReportModal';
import ReportSidebar from './ReportSidebar';

const DEFAULT_CENTER = { lat: 17.385, lng: 78.4867 };

function intensityToWeight(intensity) {
  const v = String(intensity || '').toUpperCase();
  if (v === 'ANKLE' || v === 'LOW') return 1;
  if (v === 'KNEE' || v === 'MEDIUM') return 2;
  if (v === 'VEHICLE_RISK' || v === 'HIGH') return 4;
  return 1;
}

function intensityToRadiusMeters(intensity) {
  const v = String(intensity || '').toUpperCase();
  if (v === 'VEHICLE_RISK') return 350;
  if (v === 'KNEE') return 220;
  return 140;
}

function toLatLngLiteral(report) {
  const lat = Number(report?.lat);
  const lng = Number(report?.lng);
  if (Number.isFinite(lat) && Number.isFinite(lng)) return { lat, lng };

  const coords = report?.location?.coordinates;
  if (Array.isArray(coords) && coords.length === 2) {
    const [cLng, cLat] = coords;
    if (Number.isFinite(cLat) && Number.isFinite(cLng)) return { lat: cLat, lng: cLng };
  }

  return null;
}

function makeCirclePolygonPaths(google, center, radiusMeters, points = 16) {
  const { spherical } = google.maps.geometry;
  const paths = [];
  for (let i = 0; i < points; i += 1) {
    const heading = (360 / points) * i;
    const p = spherical.computeOffset(center, radiusMeters, heading);
    paths.push({ lat: p.lat(), lng: p.lng() });
  }
  return paths;
}

function loadGoogleMaps({ apiKey }) {
  if (!apiKey) return Promise.reject(new Error('Missing REACT_APP_GOOGLE_MAPS_API_KEY'));
  if (window.google?.maps?.Map) return Promise.resolve(window.google);
  if (window.__varadhiMapsPromise) return window.__varadhiMapsPromise;

  window.__varadhiMapsPromise = new Promise((resolve, reject) => {
    const existing = document.querySelector('script[data-varadhi-maps="1"]');
    if (existing) {
      existing.addEventListener('load', () => resolve(window.google));
      existing.addEventListener('error', () => reject(new Error('Failed to load Google Maps')));
      return;
    }

    const script = document.createElement('script');
    script.dataset.varadhiMaps = '1';
    script.async = true;
    script.defer = true;
    const libs = ['visualization', 'geometry', 'places'].join(',');
    script.src = `https://maps.googleapis.com/maps/api/js?key=${encodeURIComponent(
      apiKey
    )}&libraries=${encodeURIComponent(libs)}`;
    script.onload = () => resolve(window.google);
    script.onerror = () => reject(new Error('Failed to load Google Maps'));
    document.head.appendChild(script);
  });

  return window.__varadhiMapsPromise;
}

export default function MapContainer({ apiBaseUrl = 'http://localhost:5000' }) {
  const apiKey = process.env.REACT_APP_GOOGLE_MAPS_API_KEY;

  const mapDivRef = useRef(null);
  const mapRef = useRef(null);
  const heatmapRef = useRef(null);
  const riskPolygonsRef = useRef([]);
  const directionsRendererRef = useRef(null);
  const selectedMarkerRef = useRef(null);
  const clickListenerRef = useRef(null);
  const geocoderRef = useRef(null);

  const [googleReady, setGoogleReady] = useState(false);
  const [mapsLoadError, setMapsLoadError] = useState('');

  const [reports, setReports] = useState([]);
  const [loadingReports, setLoadingReports] = useState(true);
  const [placeCache, setPlaceCache] = useState({});

  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [directionsResult, setDirectionsResult] = useState(null);
  const [routeIndex, setRouteIndex] = useState(0);
  const [routingStatus, setRoutingStatus] = useState('');

  const [reportModalOpen, setReportModalOpen] = useState(false);
  const [reportSubmitting, setReportSubmitting] = useState(false);
  const [selectedLocation, setSelectedLocation] = useState(null);

  useEffect(() => {
    let cancelled = false;
    setMapsLoadError('');
    loadGoogleMaps({ apiKey })
      .then(() => {
        if (!cancelled) setGoogleReady(true);
      })
      .catch((e) => {
        if (!cancelled) {
          setGoogleReady(false);
          setMapsLoadError(e?.message || 'Failed to load Google Maps');
        }
      });

    return () => {
      cancelled = true;
    };
  }, [apiKey]);

  useEffect(() => {
    let cancelled = false;

    async function loadActive() {
      setLoadingReports(true);
      try {
        const res = await axios.get(`${apiBaseUrl}/api/reports/active`);
        if (!cancelled) setReports(res.data || []);
      } catch {
        if (!cancelled) setReports([]);
      } finally {
        if (!cancelled) setLoadingReports(false);
      }
    }

    loadActive();
    const id = setInterval(loadActive, 30_000);
    return () => {
      cancelled = true;
      clearInterval(id);
    };
  }, [apiBaseUrl]);

  useEffect(() => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const ll = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setSelectedLocation(ll);
        mapRef.current?.panTo(ll);
      },
      () => {}
    );
  }, []);

  useEffect(() => {
    if (!googleReady || !mapDivRef.current || mapRef.current) return;
    const google = window.google;

    mapRef.current = new google.maps.Map(mapDivRef.current, {
      center: DEFAULT_CENTER,
      zoom: 12,
      styles: darkMapStyle,
      disableDefaultUI: true,
      zoomControl: true,
      fullscreenControl: true,
      clickableIcons: false,
    });

    geocoderRef.current = new google.maps.Geocoder();

    clickListenerRef.current = mapRef.current.addListener('click', (e) => {
      if (!e?.latLng) return;
      setSelectedLocation({ lat: e.latLng.lat(), lng: e.latLng.lng() });
    });

    return () => {
      if (clickListenerRef.current) {
        google.maps.event.removeListener(clickListenerRef.current);
        clickListenerRef.current = null;
      }
    };
  }, [googleReady]);

  useEffect(() => {
    if (!googleReady || !mapRef.current) return;
    const google = window.google;

    if (!selectedMarkerRef.current) {
      selectedMarkerRef.current = new google.maps.Marker({
        map: mapRef.current,
        clickable: false,
        opacity: 0.9,
      });
    }

    if (selectedLocation) {
      selectedMarkerRef.current.setPosition(selectedLocation);
      selectedMarkerRef.current.setVisible(true);
    } else {
      selectedMarkerRef.current.setVisible(false);
    }
  }, [googleReady, selectedLocation]);

  const heatmapData = useMemo(() => {
    if (!googleReady || !window.google) return [];
    return reports
      .map((r) => {
        const ll = toLatLngLiteral(r);
        if (!ll) return null;
        return {
          location: new window.google.maps.LatLng(ll.lat, ll.lng),
          weight: intensityToWeight(r.intensity || r.waterLevel),
        };
      })
      .filter(Boolean);
  }, [googleReady, reports]);

  const highRiskZonePaths = useMemo(() => {
    if (!googleReady || !window.google) return [];
    const google = window.google;
    return reports
      .filter((r) => String(r.intensity || r.waterLevel || '').toUpperCase() === 'VEHICLE_RISK')
      .map((r) => {
        const ll = toLatLngLiteral(r);
        if (!ll) return null;
        return makeCirclePolygonPaths(
          google,
          new google.maps.LatLng(ll.lat, ll.lng),
          intensityToRadiusMeters('VEHICLE_RISK')
        );
      })
      .filter(Boolean);
  }, [googleReady, reports]);

  useEffect(() => {
    if (!googleReady || !mapRef.current) return;
    const google = window.google;

    if (!heatmapRef.current) {
      heatmapRef.current = new google.maps.visualization.HeatmapLayer({
        data: [],
        map: mapRef.current,
        radius: 35,
        opacity: 0.9,
        dissipating: true,
      });
    }
    heatmapRef.current.setData(heatmapData);

    for (const poly of riskPolygonsRef.current) poly.setMap(null);
    riskPolygonsRef.current = highRiskZonePaths.map(
      (paths) =>
        new google.maps.Polygon({
          paths,
          strokeColor: '#ff3b30',
          strokeOpacity: 0.8,
          strokeWeight: 2,
          fillColor: '#ff3b30',
          fillOpacity: 0.15,
          map: mapRef.current,
        })
    );
  }, [googleReady, heatmapData, highRiskZonePaths]);

  useEffect(() => {
    if (!googleReady || !mapRef.current) return;
    const google = window.google;

    if (!directionsRendererRef.current) {
      directionsRendererRef.current = new google.maps.DirectionsRenderer({
        map: mapRef.current,
        suppressMarkers: false,
        polylineOptions: {
          strokeColor: '#2d9cdb',
          strokeOpacity: 0.95,
          strokeWeight: 5,
        },
      });
    }

    directionsRendererRef.current.setDirections(directionsResult);
    directionsRendererRef.current.setRouteIndex(routeIndex);
  }, [googleReady, directionsResult, routeIndex]);

  useEffect(() => {
    if (!googleReady || !geocoderRef.current) return;
    let cancelled = false;

    const toResolve = reports
      .map((r) => ({ id: r._id || `${r.lat}-${r.lng}-${r.timestamp || r.time}`, ll: toLatLngLiteral(r) }))
      .filter((x) => x.ll && !placeCache[x.id])
      .slice(0, 8);

    async function resolveAll() {
      for (const item of toResolve) {
        if (cancelled) return;
        const { id, ll } = item;
        await new Promise((resolve) => {
          geocoderRef.current.geocode({ location: ll }, (results, status) => {
            const formatted = status === 'OK' ? results?.[0]?.formatted_address : '';
            setPlaceCache((prev) => ({ ...prev, [id]: formatted || prev[id] || '' }));
            resolve();
          });
        });
      }
    }

    resolveAll();
    return () => {
      cancelled = true;
    };
  }, [googleReady, placeCache, reports]);

  const enrichedReports = useMemo(() => {
    return reports.map((r) => {
      const id = r._id || `${r.lat}-${r.lng}-${r.timestamp || r.time}`;
      const ts = r.timestamp || r.time;
      return {
        ...r,
        _listId: id,
        timeAgo: formatTimeAgo(ts),
        placeName: placeCache[id] || r.address || '',
      };
    });
  }, [placeCache, reports]);

  async function computeSafeRoute() {
    if (!window.google) return;
    if (!origin.trim() || !destination.trim()) {
      setRoutingStatus('Enter origin and destination.');
      return;
    }

    const google = window.google;
    const ds = new google.maps.DirectionsService();
    setRoutingStatus('Calculating route...');

    ds.route(
      {
        origin,
        destination,
        travelMode: google.maps.TravelMode.DRIVING,
        provideRouteAlternatives: true,
      },
      (result, status) => {
        if (status !== 'OK' || !result?.routes?.length) {
          setDirectionsResult(null);
          setRoutingStatus(`Directions failed: ${status}`);
          return;
        }

        const zonePolygons = highRiskZonePaths.map((paths) => new google.maps.Polygon({ paths }));
        const routeIsUnsafe = (route) => {
          const path = route?.overview_path || [];
          for (const p of path) {
            for (const poly of zonePolygons) {
              if (google.maps.geometry.poly.containsLocation(p, poly)) return true;
            }
          }
          return false;
        };

        let chosen = 0;
        let foundSafe = false;
        for (let i = 0; i < result.routes.length; i += 1) {
          if (!routeIsUnsafe(result.routes[i])) {
            chosen = i;
            foundSafe = true;
            break;
          }
        }

        setDirectionsResult(result);
        setRouteIndex(chosen);
        setRoutingStatus(
          foundSafe
            ? chosen === 0
              ? 'Route ready.'
              : `Picked alternative route #${chosen + 1} to avoid high-risk zones.`
            : 'Warning: all available routes intersect high-risk zones.'
        );
      }
    );
  }

  const detectLocation = () => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition(
      (pos) => setSelectedLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => {}
    );
  };

  const submitReport = async ({ intensity, file }) => {
    if (!selectedLocation) return;
    setReportSubmitting(true);
    try {
      if (file) {
        const form = new FormData();
        form.append('intensity', intensity);
        form.append('lat', String(selectedLocation.lat));
        form.append('lng', String(selectedLocation.lng));
        form.append('image', file);
        await axios.post(`${apiBaseUrl}/api/reports`, form);
      } else {
        await axios.post(`${apiBaseUrl}/api/reports`, {
          intensity,
          lat: selectedLocation.lat,
          lng: selectedLocation.lng,
        });
      }

      const res = await axios.get(`${apiBaseUrl}/api/reports/active`);
      setReports(res.data || []);
      setReportModalOpen(false);
    } catch {
      setRoutingStatus('Report submit failed. Check server and CORS.');
    } finally {
      setReportSubmitting(false);
    }
  };

  if (!apiKey) {
    return (
      <div className="p-4">
        Missing <code className="rounded bg-white/10 px-1 py-0.5">REACT_APP_GOOGLE_MAPS_API_KEY</code> in{' '}
        <code className="rounded bg-white/10 px-1 py-0.5">client/.env</code>.
      </div>
    );
  }

  return (
    <div className="relative h-[calc(100vh-3.5rem)] w-full overflow-hidden">
      <div ref={mapDivRef} className="h-full w-full" />

      <div className="pointer-events-none absolute inset-0">
        <div className="pointer-events-auto absolute left-4 top-4">
          <ReportSidebar
            reports={enrichedReports}
            loading={loadingReports}
            onPickReport={(r) => {
              const ll = toLatLngLiteral(r);
              if (!ll || !mapRef.current) return;
              mapRef.current.panTo(ll);
              mapRef.current.setZoom(14);
            }}
            onOpenReport={() => setReportModalOpen(true)}
            routing={{
              origin,
              setOrigin,
              destination,
              setDestination,
              onFindRoute: computeSafeRoute,
              enabled: googleReady,
              status: routingStatus,
            }}
          />
        </div>

        <div className="pointer-events-auto absolute bottom-4 left-4 rounded-2xl border border-white/10 bg-slate-950/75 px-3 py-2 text-xs text-slate-200 shadow-soft backdrop-blur">
          <div className="flex items-center gap-3">
            <span className="flex items-center gap-2">
              <span className="h-2 w-2 rounded-full bg-red-500" /> High Risk
            </span>
            <span className="flex items-center gap-2">
              <span className="h-2 w-2 rounded-full bg-yellow-400" /> Moderate
            </span>
            <span className="flex items-center gap-2">
              <span className="h-2 w-2 rounded-full bg-sky-400" /> Safe Route
            </span>
          </div>
        </div>

        <div className="pointer-events-auto absolute right-4 top-4 rounded-2xl border border-white/10 bg-slate-950/75 px-3 py-2 text-xs text-slate-300 shadow-soft backdrop-blur">
          {mapsLoadError
            ? `Maps error: ${mapsLoadError}`
            : googleReady
              ? 'Click the map to set report location'
              : 'Loading Google Maps…'}
        </div>
      </div>

      <ReportModal
        open={reportModalOpen}
        onClose={() => setReportModalOpen(false)}
        onSubmit={submitReport}
        location={selectedLocation}
        onDetectLocation={detectLocation}
        submitting={reportSubmitting}
      />
    </div>
  );
}
